window.KJV1769_STRONG_BOOKS["Eccl"] = {"osis":"Eccl","book":"전도서","verses":{"1:1":{"text":"The words of the Preacher, the son of David, king in Jerusalem.","words":[["H1697","The words",0,9],["H6953","of the Preacher",10,25],["H1121","the son",27,34],["H1732","of David",35,43],["H4428","king",45,49],["H3389","in Jerusalem",50,62]]},"1:2":{"text":"Vanity of vanities, saith the Preacher, vanity of vanities; all is vanity.","words":[["H1892","Vanity",0,6],["H1892","of vanities",7,18],["H0559","saith",20,25],["H6953","the Preacher",26,38],["H1892","vanity",40,46],["H1892","of vanities",47,58],["H1892","all is vanity",60,73]]},"1:3":{"text":"What profit hath a man of all his labour which he taketh under the sun?","words":[["H3504","What profit",0,11],["H0120","hath a man",12,22],["H5999","of all his labour",23,40],["H5998","which he taketh",41,56],["H8121","under the sun",57,70]]},"1:4":{"text":"One generation passeth away, and another generation cometh: but the earth abideth for ever.","words":[["H1755","One generation",0,14],["H1980","passeth away",15,27],["H1755","and another generation",29,51],["H0935","cometh",52,58],["H0935","cometh",52,58],["H0776","but the earth",60,73],["H5975","abideth",74,81],["H5769","for ever",82,90]]},"1:5":{"text":"The sun also ariseth, and the sun goeth down, and hasteth to his place where he arose.","words":[["H8121","The sun",0,7],["H2224","also ariseth",8,20],["H8121","and the sun",22,33],["H0935","goeth down",34,44],["H7602","and hasteth",46,57],["H4725","to his place",58,70],["H2224","where he arose",71,85]]},"1:6":{"text":"The wind goeth toward the south, and turneth about unto the north; it whirleth about continually, and the wind returneth again according to his circuits.","words":[["H7307","The wind",0,8],["H1980","goeth",9,14],["H1864","toward the south",15,31],["H5437","and turneth about",33,50],["H6828","unto the north",51,65],["H1980","it whirleth about continually",67,96],["H7307","and the wind",98,110],["H7725","returneth again",111,126],["H5439","according to his circuits",127,152]]},"1:7":{"text":"All the rivers run into the sea; yet the sea is not full; unto the place from whence the rivers come, thither they return again.","words":[["H5158","All the rivers",0,14],["H1980","run",15,18],["H3220","into the sea",19,31],["H3220","yet the sea",33,44],["H4392","is not full",45,56],["H4725","unto the place",58,72],["H5158","from whence the rivers",73,95],["H1980","come",96,100],["H7725","thither they return",102,121],["H3212","again",122,127]]},"1:8":{"text":"All things are full of labour; man cannot utter it: the eye is not satisfied with seeing, nor the ear filled with hearing.","words":[["H1697","All things",0,10],["H3023","are full of labour",11,29],["H0376","man",31,34],["H3201","cannot",35,41],["H1696","utter",42,47],["H5869","it: the eye",48,59],["H7646","is not satisfied",60,76],["H7200","with seeing",77,88],["H0241","nor the ear",90,101],["H4390","filled",102,108],["H8085","with hearing",109,121]]},"1:9":{"text":"The thing that hath been, it is that which shall be; and that which is done is that which shall be done: and there is no new thing under the sun.","words":[["H6213","The thing that hath been, it is that which shall be; and that which is done",0,75],["H6213","is that which shall be done",76,103],["H2319","and there is no new",105,124],["H8121","thing under the sun",125,144]]},"1:10":{"text":"Is there any thing whereof it may be said, See, this is new? it hath been already of old time, which was before us.","words":[["H3426","Is there",0,8],["H1697","any thing",9,18],["H0559","whereof it may be said",19,41],["H7200","See",43,46],["H2319","this is new",48,59],["H3528","it hath been already",61,81],["H5769","of old time",82,93],["H6440","which was before",95,111]]},"1:11":{"text":"There is no remembrance of former things; neither shall there be any remembrance of things that are to come with those that shall come after.","words":[["H2146","There is no remembrance",0,23],["H7223","of former",24,33],["H2146","things; neither shall there be any remembrance",34,80],["H0314","of things that are to come",81,107],["H0314","with those that shall come after",108,140]]},"1:12":{"text":"I the Preacher was king over Israel in Jerusalem.","words":[["H6953","I the Preacher",0,14],["H4428","was king",15,23],["H3478","over Israel",24,35],["H3389","in Jerusalem",36,48]]},"1:13":{"text":"And I gave my heart to seek and search out by wisdom concerning all things that are done under heaven: this sore travail hath God given to the sons of man to be exercised therewith.","words":[["H5414","And I gave",0,10],["H3820","my heart",11,19],["H1875","to seek",20,27],["H8446","and search out",28,42],["H2451","by wisdom",43,52],["H6213","concerning all things that are done",53,88],["H8064","under heaven",89,101],["H7451","this sore",103,112],["H6045","travail",113,120],["H0430","hath God",121,129],["H5414","given",130,135],["H1121","to the sons",136,147],["H0120","of man",148,154],["H6031","to be exercised",155,170]]},"1:14":{"text":"I have seen all the works that are done under the sun; and, behold, all is vanity and vexation of spirit.","words":[["H7200","I have seen",0,11],["H4639","all the works",12,25],["H6213","that are done",26,39],["H8121","under the sun",40,53],["H1892","and, behold, all is vanity",55,81],["H7469","and vexation",82,94],["H7307","of spirit",95,104]]},"1:15":{"text":"That which is crooked cannot be made straight: and that which is wanting cannot be numbered.","words":[["H5791","That which is crooked",0,21],["H3201","cannot",22,28],["H8626","be made straight",29,45],["H2642","and that which is wanting",47,72],["H3201","cannot",73,79],["H4487","be numbered",80,91]]},"1:16":{"text":"I communed with mine own heart, saying, Lo, I am come to great estate, and have gotten more wisdom than all they that have been before me in Jerusalem: yea, my heart had great experience of wisdom and knowledge.","words":[["H1696","I communed",0,10],["H3820","with mine own heart",11,30],["H0559","saying",32,38],["H1431","Lo, I am come to great estate",40,69],["H3254","and have gotten",71,86],["H2451","more wisdom",87,98],["H6440","than all they that have been before",99,134],["H3389","me in Jerusalem",135,150],["H3820","yea, my heart",152,165],["H7235","had great",166,175],["H7200","experience",176,186],["H2451","of wisdom",187,196],["H1847","and knowledge",197,210]]},"1:17":{"text":"And I gave my heart to know wisdom, and to know madness and folly: I perceived that this also is vexation of spirit.","words":[["H5414","And I gave",0,10],["H3820","my heart",11,19],["H3045","to know",20,27],["H2451","wisdom",28,34],["H3045","and to know",36,47],["H1947","madness",48,55],["H5531","and folly",56,65],["H3045","I perceived",67,78],["H1571","that this",79,88],["H7475","also is vexation",89,105],["H7307","of spirit",106,115]]},"1:18":{"text":"For in much wisdom is much grief: and he that increaseth knowledge increaseth sorrow.","words":[["H7230","For in much",0,11],["H2451","wisdom",12,18],["H7230","is much",19,26],["H3708","grief",27,32],["H3254","and he that increaseth",34,56],["H1847","knowledge",57,66],["H3254","increaseth",67,77],["H4341","sorrow",78,84]]},"2:1":{"text":"I said in mine heart, Go to now, I will prove thee with mirth, therefore enjoy pleasure: and, behold, this also is vanity.","words":[["H0559","I said",0,6],["H3820","in mine heart",7,20],["H3212","Go to now",22,31],["H5254","I will prove",33,45],["H8057","thee with mirth",46,61],["H7200","therefore enjoy",63,78],["H2896","pleasure",79,87],["H1892","and, behold, this also is vanity",89,121]]},"2:2":{"text":"I said of laughter, It is mad: and of mirth, What doeth it?","words":[["H0559","I said",0,6],["H7814","of laughter",7,18],["H1984","It is mad",20,29],["H8057","and of mirth",31,43],["H2090","What",45,49],["H6213","doeth",50,55]]},"2:3":{"text":"I sought in mine heart to give myself unto wine, yet acquainting mine heart with wisdom; and to lay hold on folly, till I might see what was that good for the sons of men, which they should do under the heaven all the days of their life.","words":[["H8446","I sought",0,8],["H3820","in mine heart",9,22],["H4900","to give",23,30],["H1320","myself",31,37],["H3196","unto wine",38,47],["H5090","yet acquainting",49,64],["H3820","mine heart",65,75],["H2451","with wisdom",76,87],["H0270","and to lay hold",89,104],["H5531","on folly",105,113],["H7200","till I might see",115,131],["H2896","what was that good",132,150],["H1121","for the sons",151,163],["H0120","of men",164,170],["H6213","which they should do",172,192],["H8064","under the heaven",193,209],["H4557","all",210,213],["H3117","the days",214,222],["H2416","of their life",223,236]]},"2:4":{"text":"I made me great works; I builded me houses; I planted me vineyards:","words":[["H1431","I made me great",0,15],["H4639","works",16,21],["H1129","I builded",23,32],["H1004","me houses",33,42],["H5193","I planted",44,53],["H3754","me vineyards",54,66]]},"2:5":{"text":"I made me gardens and orchards, and I planted trees in them of all kind of fruits:","words":[["H6213","I made",0,6],["H1593","me gardens",7,17],["H6508","and orchards",18,30],["H5193","and I planted",32,45],["H6086","trees",46,51],["H6529","in them of all kind of fruits",52,81]]},"2:6":{"text":"I made me pools of water, to water therewith the wood that bringeth forth trees:","words":[["H6213","I made",0,6],["H1295","me pools",7,15],["H4325","of water",16,24],["H8248","to water",26,34],["H3293","therewith the wood",35,53],["H6779","that bringeth forth",54,73],["H6086","trees",74,79]]},"2:7":{"text":"I got me servants and maidens, and had servants born in my house; also I had great possessions of great and small cattle above all that were in Jerusalem before me:","words":[["H7069","I got",0,5],["H5650","me servants",6,17],["H8198","and maidens",18,29],["H1121","and had servants born",31,52],["H1004","in my house",53,64],["H7235","also I had great",66,82],["H4735","possessions",83,94],["H1241","of great",95,103],["H6629","and small cattle",104,120],["H3389","above all that were in Jerusalem",121,153],["H6440","before",154,160]]},"2:8":{"text":"I gathered me also silver and gold, and the peculiar treasure of kings and of the provinces: I gat me men singers and women singers, and the delights of the sons of men, as musical instruments, and that of all sorts.","words":[["H3664","I gathered",0,10],["H3701","me also silver",11,25],["H2091","and gold",26,34],["H5459","and the peculiar treasure",36,61],["H4428","of kings",62,70],["H4082","and of the provinces",71,91],["H6213","I gat",93,98],["H7891","me men singers",99,113],["H7891","and women singers",114,131],["H8588","and the delights",133,149],["H1121","of the sons",150,161],["H0120","of men",162,168],["H7705","as musical instruments",170,192],["H7705","as musical instruments",170,192]]},"2:9":{"text":"So I was great, and increased more than all that were before me in Jerusalem: also my wisdom remained with me.","words":[["H1431","So I was great",0,14],["H3254","and increased",16,29],["H6440","more than all that were before",30,60],["H3389","me in Jerusalem",61,76],["H2451","also my wisdom",78,92],["H5975","remained",93,101]]},"2:10":{"text":"And whatsoever mine eyes desired I kept not from them, I withheld not my heart from any joy; for my heart rejoiced in all my labour: and this was my portion of all my labour.","words":[["H5869","And whatsoever mine eyes",0,24],["H7592","desired",25,32],["H0680","I kept",33,39],["H4513","not from them, I withheld",40,65],["H3820","not my heart",66,78],["H8057","from any joy",79,91],["H3820","for my heart",93,105],["H8056","rejoiced",106,114],["H5999","in all my labour",115,131],["H2506","and this was my portion",133,156],["H5999","of all my labour",157,173]]},"2:11":{"text":"Then I looked on all the works that my hands had wrought, and on the labour that I had laboured to do: and, behold, all was vanity and vexation of spirit, and there was no profit under the sun.","words":[["H6437","Then I looked",0,13],["H4639","on all the works",14,30],["H3027","that my hands",31,44],["H6213","had wrought",45,56],["H5999","and on the labour",58,75],["H5998","that I had laboured",76,95],["H6213","to do",96,101],["H1892","and, behold, all was vanity",103,130],["H7469","and vexation",131,143],["H7307","of spirit",144,153],["H3504","and there was no profit",155,178],["H8121","under the sun",179,192]]},"2:12":{"text":"And I turned myself to behold wisdom, and madness, and folly: for what can the man do that cometh after the king? even that which hath been already done.","words":[["H6437","And I turned",0,12],["H7200","myself to behold",13,29],["H2451","wisdom",30,36],["H1947","and madness",38,49],["H5531","and folly",51,60],["H0120","for what can the man",62,82],["H0935","do that cometh",83,97],["H0310","after",98,103],["H4428","the king",104,112],["H3528","even that which hath been already",114,147],["H6213","done",148,152]]},"2:13":{"text":"Then I saw that wisdom excelleth folly, as far as light excelleth darkness.","words":[["H7200","Then I saw",0,10],["H3426","that",11,15],["H2451","wisdom",16,22],["H3504","excelleth",23,32],["H5531","folly",33,38],["H0216","as far as light",40,55],["H3504","excelleth",56,65],["H2822","darkness",66,74]]},"2:14":{"text":"The wise man's eyes are in his head; but the fool walketh in darkness: and I myself perceived also that one event happeneth to them all.","words":[["H2450","The wise man's",0,14],["H5869","eyes",15,19],["H7218","are in his head",20,35],["H3684","but the fool",37,49],["H1980","walketh",50,57],["H2822","in darkness",58,69],["H3045","and I myself perceived",71,93],["H0259","also that one",94,107],["H4745","event",108,113],["H7136","happeneth",114,123]]},"2:15":{"text":"Then said I in my heart, As it happeneth to the fool, so it happeneth even to me; and why was I then more wise? Then I said in my heart, that this also is vanity.","words":[["H0227","Then",0,4],["H0559","said",5,9],["H3820","I in my heart",10,23],["H4745","As it happeneth",25,40],["H3684","to the fool",41,52],["H7136","so it happeneth",54,69],["H1571","even to me",70,80],["H3148","and why was I then more",82,105],["H2449","wise",106,110],["H1696","Then I said",112,123],["H3820","in my heart",124,135],["H1892","that this also is vanity",137,161]]},"2:16":{"text":"For there is no remembrance of the wise more than of the fool for ever; seeing that which now is in the days to come shall all be forgotten. And how dieth the wise man? as the fool.","words":[["H2146","For there is no remembrance",0,27],["H2450","of the wise",28,39],["H5973","more than",40,49],["H3684","of the fool",50,61],["H5769","for ever",62,70],["H3528","seeing that which now",72,93],["H3117","is in the days",94,108],["H0935","to come",109,116],["H7911","shall all be forgotten",117,139],["H4191","And how dieth",141,154],["H2450","the wise",155,163],["H3684","man? as the fool",164,180]]},"2:17":{"text":"Therefore I hated life; because the work that is wrought under the sun is grievous unto me: for all is vanity and vexation of spirit.","words":[["H8130","Therefore I hated",0,17],["H2416","life",18,22],["H4639","because the work",24,40],["H6213","that is wrought",41,56],["H8121","under the sun",57,70],["H7451","is grievous",71,82],["H1892","unto me: for all is vanity",83,109],["H7469","and vexation",110,122],["H7307","of spirit",123,132]]},"2:18":{"text":"Yea, I hated all my labour which I had taken under the sun: because I should leave it unto the man that shall be after me.","words":[["H8130","Yea, I hated",0,12],["H5999","all my labour",13,26],["H6001","which I had taken",27,44],["H8121","under the sun",45,58],["H3240","because I should leave",60,82],["H0120","it unto the man",83,98],["H0310","that shall be after",99,118]]},"2:19":{"text":"And who knoweth whether he shall be a wise man or a fool? yet shall he have rule over all my labour wherein I have laboured, and wherein I have shewed myself wise under the sun. This is also vanity.","words":[["H3045","And who knoweth",0,15],["H2450","whether he shall be a wise",16,42],["H5530","man or a fool",43,56],["H7980","yet shall he have rule",58,80],["H5999","over all my labour",81,99],["H5998","wherein I have laboured",100,123],["H2449","and wherein I have shewed myself wise",125,162],["H8121","under the sun",163,176],["H1892","This is also vanity",178,197]]},"2:20":{"text":"Therefore I went about to cause my heart to despair of all the labour which I took under the sun.","words":[["H5437","Therefore I went about",0,22],["H2976","to cause",23,31],["H3820","my heart",32,40],["H2976","to despair",41,51],["H5999","of all the labour",52,69],["H5998","which I took",70,82],["H8121","under the sun",83,96]]},"2:21":{"text":"For there is a man whose labour is in wisdom, and in knowledge, and in equity; yet to a man that hath not laboured therein shall he leave it for his portion. This also is vanity and a great evil.","words":[["H3426","For there is",0,12],["H0120","a man",13,18],["H5999","whose labour",19,31],["H2451","is in wisdom",32,44],["H1847","and in knowledge",46,62],["H3788","and in equity",64,77],["H0120","yet to a man",79,91],["H5998","that hath not laboured",92,114],["H5414","therein shall he leave",115,137],["H2506","it for his portion",138,156],["H1892","This also is vanity",158,177],["H7227","and a great",178,189],["H7451","evil",190,194]]},"2:22":{"text":"For what hath man of all his labour, and of the vexation of his heart, wherein he hath laboured under the sun?","words":[["H1933","For what hath",0,13],["H0120","man",14,17],["H5999","of all his labour",18,35],["H7475","and of the vexation",37,56],["H3820","of his heart",57,69],["H1931","wherein",71,78],["H6001","he hath laboured",79,95],["H8121","under the sun",96,109]]},"2:23":{"text":"For all his days are sorrows, and his travail grief; yea, his heart taketh not rest in the night. This is also vanity.","words":[["H3117","For all his days",0,16],["H4341","are sorrows",17,28],["H6045","and his travail",30,45],["H3708","grief",46,51],["H3820","yea, his heart",53,67],["H7901","taketh not rest",68,83],["H3915","in the night",84,96],["H1892","This is also vanity",98,117]]},"2:24":{"text":"There is nothing better for a man, than that he should eat and drink, and that he should make his soul enjoy good in his labour. This also I saw, that it was from the hand of God.","words":[["H2896","There is nothing better",0,23],["H0120","for a man",24,33],["H0398","than that he should eat",35,58],["H8354","and drink",59,68],["H5315","and that he should make his soul",70,102],["H7200","enjoy",103,108],["H2896","good",109,113],["H5999","in his labour",114,127],["H2090","This",129,133],["H7200","also I saw",134,144],["H3027","that it was from the hand",146,171],["H0430","of God",172,178]]},"2:25":{"text":"For who can eat, or who else can hasten hereunto, more than I?","words":[["H0398","For who can eat",0,15],["H2363","or who else can hasten",17,39],["H2351","hereunto, more",40,54]]},"2:26":{"text":"For God giveth to a man that is good in his sight wisdom, and knowledge, and joy: but to the sinner he giveth travail, to gather and to heap up, that he may give to him that is good before God. This also is vanity and vexation of spirit.","words":[["H5414","For God giveth",0,14],["H0120","to a man",15,23],["H2896","that is good",24,36],["H6440","in his sight",37,49],["H2451","wisdom",50,56],["H1847","and knowledge",58,71],["H8057","and joy",73,80],["H2398","but to the sinner",82,99],["H5414","he giveth",100,109],["H6045","travail",110,117],["H0622","to gather",119,128],["H3664","and to heap up",129,143],["H5414","that he may give",145,161],["H2896","to him that is good",162,181],["H6440","before",182,188],["H0430","God",189,192],["H1892","This also is vanity",194,213],["H7469","and vexation",214,226],["H7307","of spirit",227,236]]},"3:1":{"text":"To every thing there is a season, and a time to every purpose under the heaven:","words":[["H2165","To every thing there is a season",0,32],["H6256","and a time",34,44],["H2656","to every purpose",45,61],["H8064","under the heaven",62,78]]},"3:2":{"text":"A time to be born, and a time to die; a time to plant, and a time to pluck up that which is planted;","words":[["H6256","A time",0,6],["H3205","to be born",7,17],["H6256","and a time",19,29],["H4191","to die",30,36],["H6256","a time",38,44],["H5193","to plant",45,53],["H6256","and a time",55,65],["H6131","to pluck up",66,77],["H5193","that which is planted",78,99]]},"3:3":{"text":"A time to kill, and a time to heal; a time to break down, and a time to build up;","words":[["H6256","A time",0,6],["H2026","to kill",7,14],["H6256","and a time",16,26],["H7495","to heal",27,34],["H6256","a time",36,42],["H6555","to break down",43,56],["H6256","and a time",58,68],["H1129","to build up",69,80]]},"3:4":{"text":"A time to weep, and a time to laugh; a time to mourn, and a time to dance;","words":[["H6256","A time",0,6],["H1058","to weep",7,14],["H6256","and a time",16,26],["H7832","to laugh",27,35],["H6256","a time",37,43],["H5594","to mourn",44,52],["H6256","and a time",54,64],["H7540","to dance",65,73]]},"3:5":{"text":"A time to cast away stones, and a time to gather stones together; a time to embrace, and a time to refrain from embracing;","words":[["H6256","A time",0,6],["H7993","to cast away",7,19],["H0068","stones",20,26],["H6256","and a time",28,38],["H3664","to gather",39,48],["H0068","stones",49,55],["H3664","together",56,64],["H6256","a time",66,72],["H2263","to embrace",73,83],["H6256","and a time",85,95],["H7368","to refrain",96,106],["H2263","from embracing",107,121]]},"3:6":{"text":"A time to get, and a time to lose; a time to keep, and a time to cast away;","words":[["H6256","A time",0,6],["H1245","to get",7,13],["H6256","and a time",15,25],["H0006","to lose",26,33],["H6256","a time",35,41],["H8104","to keep",42,49],["H6256","and a time",51,61],["H7993","to cast away",62,74]]},"3:7":{"text":"A time to rend, and a time to sew; a time to keep silence, and a time to speak;","words":[["H6256","A time",0,6],["H7167","to rend",7,14],["H6256","and a time",16,26],["H8609","to sew",27,33],["H6256","a time",35,41],["H2814","to keep silence",42,57],["H6256","and a time",59,69],["H1696","to speak",70,78]]},"3:8":{"text":"A time to love, and a time to hate; a time of war, and a time of peace.","words":[["H6256","A time",0,6],["H0157","to love",7,14],["H6256","and a time",16,26],["H8130","to hate",27,34],["H6256","a time",36,42],["H4421","of war",43,49],["H6256","and a time",51,61],["H7965","of peace",62,70]]},"3:9":{"text":"What profit hath he that worketh in that wherein he laboureth?","words":[["H3504","What profit",0,11],["H6213","hath he that worketh",12,32],["H0834","in that wherein",33,48],["H6001","he laboureth",49,61]]},"3:10":{"text":"I have seen the travail, which God hath given to the sons of men to be exercised in it.","words":[["H7200","I have seen",0,11],["H6045","the travail",12,23],["H0430","which God",25,34],["H5414","hath given",35,45],["H1121","to the sons",46,57],["H0120","of men",58,64],["H6031","to be exercised",65,80]]},"3:11":{"text":"He hath made every thing beautiful in his time: also he hath set the world in their heart, so that no man can find out the work that God maketh from the beginning to the end.","words":[["H6213","He hath made",0,12],["H3303","every thing beautiful",13,34],["H6256","in his time",35,46],["H5414","also he hath set",48,64],["H5769","the world",65,74],["H3820","in their heart",75,89],["H1097","so that",91,98],["H0120","no man",99,105],["H4672","can find out",106,118],["H4639","the work",119,127],["H0430","that God",128,136],["H6213","maketh",137,143],["H7218","from the beginning",144,162],["H5490","to the end",163,173]]},"3:12":{"text":"I know that there is no good in them, but for a man to rejoice, and to do good in his life.","words":[["H3045","I know",0,6],["H2896","that there is no good",7,28],["H8055","in them, but for a man to rejoice",29,62],["H6213","and to do",64,73],["H2896","good",74,78],["H2416","in his life",79,90]]},"3:13":{"text":"And also that every man should eat and drink, and enjoy the good of all his labour, it is the gift of God.","words":[["H0120","And also that every man",0,23],["H0398","should eat",24,34],["H8354","and drink",35,44],["H7200","and enjoy",46,55],["H2896","the good",56,64],["H5999","of all his labour",65,82],["H4991","it is the gift",84,98],["H0430","of God",99,105]]},"3:14":{"text":"I know that, whatsoever God doeth, it shall be for ever: nothing can be put to it, nor any thing taken from it: and God doeth it, that men should fear before him.","words":[["H3045","I know",0,6],["H0430","that, whatsoever God",7,27],["H6213","doeth",28,33],["H5769","it shall be for ever",35,55],["H0369","nothing",57,64],["H3254","can be put",65,75],["H1639","to it, nor any thing taken",76,102],["H0430","from it: and God",103,119],["H6213","doeth",120,125],["H3372","it, that men should fear",126,150],["H6440","before",151,157]]},"3:15":{"text":"That which hath been is now; and that which is to be hath already been; and God requireth that which is past.","words":[["H3528","That which hath been is now",0,27],["H3528","and that which is to be hath already",29,65],["H0430","been; and God",66,79],["H1245","requireth",80,89],["H7291","that which is past",90,108]]},"3:16":{"text":"And moreover I saw under the sun the place of judgment, that wickedness was there; and the place of righteousness, that iniquity was there.","words":[["H7200","And moreover I saw",0,18],["H8121","under the sun",19,32],["H4725","the place",33,42],["H4941","of judgment",43,54],["H7562","that wickedness",56,71],["H4725","was there; and the place",72,96],["H6664","of righteousness",97,113],["H7562","that iniquity",115,128]]},"3:17":{"text":"I said in mine heart, God shall judge the righteous and the wicked: for there is a time there for every purpose and for every work.","words":[["H0559","I said",0,6],["H3820","in mine heart",7,20],["H0430","God",22,25],["H8199","shall judge",26,37],["H6662","the righteous",38,51],["H7563","and the wicked",52,66],["H6256","for there is a time",68,87],["H2656","there for every purpose",88,111],["H4639","and for every work",112,130]]},"3:18":{"text":"I said in mine heart concerning the estate of the sons of men, that God might manifest them, and that they might see that they themselves are beasts.","words":[["H0559","I said",0,6],["H3820","in mine heart",7,20],["H1700","concerning the estate",21,42],["H1121","of the sons",43,54],["H0120","of men",55,61],["H0430","that God",63,71],["H1305","might manifest",72,86],["H7200","them, and that they might see",87,116],["H1992","that they",117,126],["H0929","themselves are beasts",127,148]]},"3:19":{"text":"For that which befalleth the sons of men befalleth beasts; even one thing befalleth them: as the one dieth, so dieth the other; yea, they have all one breath; so that a man hath no preeminence above a beast: for all is vanity.","words":[["H4745","For that which befalleth",0,24],["H1121","the sons",25,33],["H0120","of men",34,40],["H4745","befalleth",41,50],["H0929","beasts",51,57],["H0259","even one thing",59,73],["H4745","befalleth",74,83],["H4194","them: as the one dieth",84,106],["H4194","so dieth",108,116],["H2088","the other",117,126],["H0259","yea, they have all one",128,150],["H7307","breath",151,157],["H0120","so that a man",159,172],["H4195","hath no preeminence",173,192],["H0929","above a beast",193,206],["H1892","for all is vanity",208,225]]},"3:20":{"text":"All go unto one place; all are of the dust, and all turn to dust again.","words":[["H1980","All go",0,6],["H0259","unto one",7,15],["H4725","place",16,21],["H6083","all are of the dust",23,42],["H7725","and all turn",44,56],["H6083","to dust",57,64],["H7725","again",65,70]]},"3:21":{"text":"Who knoweth the spirit of man that goeth upward, and the spirit of the beast that goeth downward to the earth?","words":[["H3045","Who knoweth",0,11],["H7307","the spirit",12,22],["H1121","of man",23,29],["H0120","of man",23,29],["H5927","that goeth",30,40],["H4605","upward",41,47],["H7307","and the spirit",49,63],["H0929","of the beast",64,76],["H3381","that goeth",77,87],["H4295","downward",88,96],["H0776","to the earth",97,109]]},"3:22":{"text":"Wherefore I perceive that there is nothing better, than that a man should rejoice in his own works; for that is his portion: for who shall bring him to see what shall be after him?","words":[["H7200","Wherefore I perceive",0,20],["H2896","that there is nothing better",21,49],["H0120","than that a man",51,66],["H8055","should rejoice",67,81],["H4639","in his own works",82,98],["H2506","for that is his portion",100,123],["H0935","for who shall bring",125,144],["H7200","him to see",145,155],["H0310","what shall be after",156,175]]},"4:1":{"text":"So I returned, and considered all the oppressions that are done under the sun: and behold the tears of such as were oppressed, and they had no comforter; and on the side of their oppressors there was power; but they had no comforter.","words":[["H7725","So I returned",0,13],["H7200","and considered",15,29],["H6217","all the oppressions",30,49],["H6213","that are done",50,63],["H8121","under the sun",64,77],["H1832","and behold the tears",79,99],["H6231","of such as were oppressed",100,125],["H5162","and they had no comforter",127,152],["H3027","and on the side",154,169],["H6231","of their oppressors",170,189],["H3581","there was power",190,205],["H5162","but they had no comforter",207,232]]},"4:2":{"text":"Wherefore I praised the dead which are already dead more than the living which are yet alive.","words":[["H7623","Wherefore I praised",0,19],["H4191","the dead",20,28],["H3528","which are already",29,46],["H4191","dead",47,51],["H2416","more than the living",52,72],["H5728","which are yet",73,86],["H2416","alive",87,92]]},"4:3":{"text":"Yea, better is he than both they, which hath not yet been, who hath not seen the evil work that is done under the sun.","words":[["H2896","Yea, better",0,11],["H8147","is he than both",12,27],["H5728","they, which hath not yet",28,52],["H7200","been, who hath not seen",53,76],["H7451","the evil",77,85],["H4639","work",86,90],["H6213","that is done",91,103],["H8121","under the sun",104,117]]},"4:4":{"text":"Again, I considered all travail, and every right work, that for this a man is envied of his neighbour. This is also vanity and vexation of spirit.","words":[["H7200","Again, I considered",0,19],["H5999","all travail",20,31],["H3788","and every right",33,48],["H4639","work",49,53],["H0376","that for this a man",55,74],["H7068","is envied",75,84],["H7453","of his neighbour",85,101],["H1892","This is also vanity",103,122],["H7469","and vexation",123,135],["H7307","of spirit",136,145]]},"4:5":{"text":"The fool foldeth his hands together, and eateth his own flesh.","words":[["H3684","The fool",0,8],["H2263","foldeth",9,16],["H3027","his hands",17,26],["H2263","together",27,35],["H0398","and eateth",37,47],["H1320","his own flesh",48,61]]},"4:6":{"text":"Better is an handful with quietness, than both the hands full with travail and vexation of spirit.","words":[["H2896","Better",0,6],["H3709","is an handful",7,20],["H5183","with quietness",21,35],["H2651","than both the hands",37,56],["H4393","full",57,61],["H5999","with travail",62,74],["H7469","and vexation",75,87],["H7307","of spirit",88,97]]},"4:7":{"text":"Then I returned, and I saw vanity under the sun.","words":[["H7725","Then I returned",0,15],["H7200","and I saw",17,26],["H1892","vanity",27,33],["H8121","under the sun",34,47]]},"4:8":{"text":"There is one alone, and there is not a second; yea, he hath neither child nor brother: yet is there no end of all his labour; neither is his eye satisfied with riches; neither saith he, For whom do I labour, and bereave my soul of good? This is also vanity, yea, it is a sore travail.","words":[["H3426","There is",0,8],["H0259","one",9,12],["H8145","alone, and there is not a second",13,45],["H1121","yea, he hath neither child",47,73],["H0251","nor brother",74,85],["H7093","yet is there no end",87,106],["H5999","of all his labour",107,124],["H5869","neither is his eye",126,144],["H7646","satisfied",145,154],["H6239","with riches",155,166],["H6001","neither saith he, For whom do I labour",168,206],["H2637","and bereave",208,219],["H5315","my soul",220,227],["H2896","of good",228,235],["H1892","This is also vanity",237,256],["H7451","yea, it is a sore",258,275],["H6045","travail",276,283]]},"4:9":{"text":"Two are better than one; because they have a good reward for their labour.","words":[["H8147","Two",0,3],["H2896","are better",4,14],["H0259","than one",15,23],["H3426","because they have",25,42],["H2896","a good",43,49],["H7939","reward",50,56],["H5999","for their labour",57,73]]},"4:10":{"text":"For if they fall, the one will lift up his fellow: but woe to him that is alone when he falleth; for he hath not another to help him up.","words":[["H5307","For if they fall",0,16],["H0259","the one",18,25],["H6965","will lift up",26,38],["H2270","his fellow",39,49],["H0337","but woe",51,58],["H0259","to him that is alone",59,79],["H5307","when he falleth",80,95],["H8145","for he hath not another",97,120],["H6965","to help him up",121,135]]},"4:11":{"text":"Again, if two lie together, then they have heat: but how can one be warm alone?","words":[["H1571","Again",0,5],["H8147","if two",7,13],["H7901","lie together",14,26],["H2552","then they have heat",28,47],["H0259","but how can one",49,64],["H3179","be warm",65,72]]},"4:12":{"text":"And if one prevail against him, two shall withstand him; and a threefold cord is not quickly broken.","words":[["H0259","And if one",0,10],["H8630","prevail",11,18],["H8147","against him, two",19,35],["H5975","shall withstand",36,51],["H8027","him; and a threefold",52,72],["H2339","cord",73,77],["H4120","is not quickly",78,92],["H5423","broken",93,99]]},"4:13":{"text":"Better is a poor and a wise child than an old and foolish king, who will no more be admonished.","words":[["H2896","Better",0,6],["H4542","is a poor",7,16],["H2450","and a wise",17,27],["H3206","child",28,33],["H2205","than an old",34,45],["H3684","and foolish",46,57],["H4428","king",58,62],["H3045","who will",64,72],["H2094","no more be admonished",73,94]]},"4:14":{"text":"For out of prison he cometh to reign; whereas also he that is born in his kingdom becometh poor.","words":[["H0631","For out of prison",0,17],["H1004","For out of prison",0,17],["H3318","he cometh",18,27],["H4427","to reign",28,36],["H3205","whereas also he that is born",38,66],["H4438","in his kingdom",67,81],["H7326","becometh poor",82,95]]},"4:15":{"text":"I considered all the living which walk under the sun, with the second child that shall stand up in his stead.","words":[["H7200","I considered",0,12],["H2416","all the living",13,27],["H1980","which walk",28,38],["H8121","under the sun",39,52],["H8145","with the second",54,69],["H3206","child",70,75],["H5975","that shall stand up",76,95]]},"4:16":{"text":"There is no end of all the people, even of all that have been before them: they also that come after shall not rejoice in him. Surely this also is vanity and vexation of spirit.","words":[["H7093","There is no end",0,15],["H5971","of all the people",16,33],["H6440","even of all that have been before",35,68],["H0314","them: they also that come after",69,100],["H8055","shall not rejoice",101,118],["H1892","in him. Surely this also is vanity",119,153],["H7475","and vexation",154,166],["H7307","of spirit",167,176]]},"5:1":{"text":"Keep thy foot when thou goest to the house of God, and be more ready to hear, than to give the sacrifice of fools: for they consider not that they do evil.","words":[["H8104","Keep",0,4],["H7272","thy foot",5,13],["H3212","when thou goest",14,29],["H1004","to the house",30,42],["H0430","of God",43,49],["H7138","and be more ready",51,68],["H8085","to hear",69,76],["H5414","than to give",78,90],["H2077","the sacrifice",91,104],["H3684","of fools",105,113],["H3045","for they consider",115,132],["H6213","not that they do",133,149],["H7451","evil",150,154]]},"5:2":{"text":"Be not rash with thy mouth, and let not thine heart be hasty to utter any thing before God: for God is in heaven, and thou upon earth: therefore let thy words be few.","words":[["H0926","Be not rash",0,11],["H6310","with thy mouth",12,26],["H3820","and let not thine heart",28,51],["H4116","be hasty",52,60],["H3318","to utter",61,69],["H1697","any thing",70,79],["H6440","before",80,86],["H0430","God",87,90],["H0430","for God",92,99],["H8064","is in heaven",100,112],["H0776","and thou upon earth",114,133],["H1697","therefore let thy words",135,158],["H4592","be few",159,165]]},"5:3":{"text":"For a dream cometh through the multitude of business; and a fool's voice is known by multitude of words.","words":[["H2472","For a dream",0,11],["H0935","cometh",12,18],["H7230","through the multitude",19,40],["H6045","of business",41,52],["H3684","and a fool's",54,66],["H6963","voice",67,72],["H7230","is known by multitude",73,94],["H1697","of words",95,103]]},"5:4":{"text":"When thou vowest a vow unto God, defer not to pay it; for he hath no pleasure in fools: pay that which thou hast vowed.","words":[["H5087","When thou vowest",0,16],["H5088","a vow",17,22],["H0430","unto God",23,31],["H0309","defer",33,38],["H7999","not to pay",39,49],["H2656","it; for he hath no pleasure",50,77],["H3684","in fools",78,86],["H7999","pay",88,91],["H5087","that which thou hast vowed",92,118]]},"5:5":{"text":"Better is it that thou shouldest not vow, than that thou shouldest vow and not pay.","words":[["H2896","Better",0,6],["H5087","is it that thou shouldest not vow",7,40],["H5087","than that thou shouldest vow",42,70],["H7999","and not pay",71,82]]},"5:6":{"text":"Suffer not thy mouth to cause thy flesh to sin; neither say thou before the angel, that it was an error: wherefore should God be angry at thy voice, and destroy the work of thine hands?","words":[["H5414","Suffer",0,6],["H6310","not thy mouth",7,20],["H1320","to cause thy flesh",21,39],["H2398","to sin",40,46],["H0559","neither say",48,59],["H6440","thou before",60,71],["H4397","the angel",72,81],["H7684","that it was an error",83,103],["H0430","wherefore should God",105,125],["H7107","be angry",126,134],["H6963","at thy voice",135,147],["H2254","and destroy",149,160],["H4639","the work",161,169],["H3027","of thine hands",170,184]]},"5:7":{"text":"For in the multitude of dreams and many words there are also divers vanities: but fear thou God.","words":[["H7230","For in the multitude",0,20],["H2472","of dreams",21,30],["H7235","and many",31,39],["H1697","words",40,45],["H1892","there are also divers vanities",46,76],["H3372","but fear",78,86],["H0430","thou God",87,95]]},"5:8":{"text":"If thou seest the oppression of the poor, and violent perverting of judgment and justice in a province, marvel not at the matter: for he that is higher than the highest regardeth; and there be higher than they.","words":[["H7200","If thou seest",0,13],["H6233","the oppression",14,28],["H7326","of the poor",29,40],["H1499","and violent",42,53],["H4941","perverting of judgment",54,76],["H6664","and justice",77,88],["H4082","in a province",89,102],["H8539","marvel",104,110],["H2656","not at the matter",111,128],["H1364","for he that is higher",130,151],["H1364","than the highest",152,168],["H8104","regardeth",169,178],["H1364","and there be higher",180,199],["H5921","than they",200,209]]},"5:9":{"text":"Moreover the profit of the earth is for all: the king himself is served by the field.","words":[["H3504","Moreover the profit",0,19],["H0776","of the earth",20,32],["H4428","is for all: the king",33,53],["H5647","himself is served",54,71],["H7704","by the field",72,84]]},"5:10":{"text":"He that loveth silver shall not be satisfied with silver; nor he that loveth abundance with increase: this is also vanity.","words":[["H0157","He that loveth",0,14],["H3701","silver",15,21],["H7646","shall not be satisfied",22,44],["H3701","with silver",45,56],["H0157","nor he that loveth",58,76],["H1995","abundance",77,86],["H8393","with increase",87,100],["H1892","this is also vanity",102,121]]},"5:11":{"text":"When goods increase, they are increased that eat them: and what good is there to the owners thereof, saving the beholding of them with their eyes?","words":[["H2896","When goods",0,10],["H7235","increase",11,19],["H7231","they are increased",21,39],["H0398","that eat",40,48],["H3788","them: and what good",49,68],["H1167","is there to the owners",69,91],["H0518","thereof, saving",92,107],["H7207","the beholding",108,121],["H7212","the beholding",108,121],["H5869","of them with their eyes",122,145]]},"5:12":{"text":"The sleep of a labouring man is sweet, whether he eat little or much: but the abundance of the rich will not suffer him to sleep.","words":[["H8142","The sleep",0,9],["H5647","of a labouring man",10,28],["H4966","is sweet",29,37],["H0398","whether he eat",39,53],["H4592","little",54,60],["H7235","or much",61,68],["H7647","but the abundance",70,87],["H6223","of the rich",88,99],["H3240","will not suffer",100,115],["H3462","him to sleep",116,128]]},"5:13":{"text":"There is a sore evil which I have seen under the sun, namely, riches kept for the owners thereof to their hurt.","words":[["H3426","There is",0,8],["H2470","a sore",9,15],["H7451","evil",16,20],["H7200","which I have seen",21,38],["H8121","under the sun",39,52],["H6239","namely, riches",54,68],["H8104","kept",69,73],["H1167","for the owners",74,88],["H7451","thereof to their hurt",89,110]]},"5:14":{"text":"But those riches perish by evil travail: and he begetteth a son, and there is nothing in his hand.","words":[["H6239","But those riches",0,16],["H0006","perish",17,23],["H7451","by evil",24,31],["H6045","travail",32,39],["H3205","and he begetteth",41,57],["H1121","a son",58,63],["H3972","and there is nothing",65,85],["H3027","in his hand",86,97]]},"5:15":{"text":"As he came forth of his mother's womb, naked shall he return to go as he came, and shall take nothing of his labour, which he may carry away in his hand.","words":[["H3318","As he came forth",0,16],["H0517","of his mother's",17,32],["H0990","womb",33,37],["H6174","naked",39,44],["H7725","shall he return",45,60],["H3212","to go",61,66],["H0935","as he came",67,77],["H5375","and shall take",79,93],["H3972","nothing",94,101],["H5999","of his labour",102,115],["H3212","which he may carry away",117,140],["H3027","in his hand",141,152]]},"5:16":{"text":"And this also is a sore evil, that in all points as he came, so shall he go: and what profit hath he that hath laboured for the wind?","words":[["H2090","And this",0,8],["H2470","also is a sore",9,23],["H7451","evil",24,28],["H5980","that in all points",30,48],["H0935","as he came",49,59],["H3212","so shall he go",61,75],["H3504","and what profit",77,92],["H5998","hath he that hath laboured",93,119],["H7307","for the wind",120,132]]},"5:17":{"text":"All his days also he eateth in darkness, and he hath much sorrow and wrath with his sickness.","words":[["H3117","All his days",0,12],["H0398","also he eateth",13,27],["H2822","in darkness",28,39],["H7235","and he hath much",41,57],["H3707","sorrow",58,64],["H7110","and wrath",65,74],["H2483","with his sickness",75,92]]},"5:18":{"text":"Behold that which I have seen: it is good and comely for one to eat and to drink, and to enjoy the good of all his labour that he taketh under the sun all the days of his life, which God giveth him: for it is his portion.","words":[["H7200","Behold that which I have seen",0,29],["H2896","it is good",31,41],["H3303","and comely",42,52],["H0398","for one to eat",53,67],["H8354","and to drink",68,80],["H7200","and to enjoy",82,94],["H2896","the good",95,103],["H5999","of all his labour",104,121],["H5998","that he taketh",122,136],["H8121","under the sun",137,150],["H4557","all",151,154],["H3117","the days",155,163],["H2416","of his life",164,175],["H0430","which God",177,186],["H5414","giveth",187,193],["H2506","him: for it is his portion",194,220]]},"5:19":{"text":"Every man also to whom God hath given riches and wealth, and hath given him power to eat thereof, and to take his portion, and to rejoice in his labour; this is the gift of God.","words":[["H0120","Every man",0,9],["H0430","also to whom God",10,26],["H5414","hath given",27,37],["H6239","riches",38,44],["H5233","and wealth",45,55],["H7980","and hath given him power",57,81],["H0398","to eat",82,88],["H5375","thereof, and to take",89,109],["H2506","his portion",110,121],["H8055","and to rejoice",123,137],["H5999","in his labour",138,151],["H2090","this",153,157],["H4991","is the gift",158,169],["H0430","of God",170,176]]},"5:20":{"text":"For he shall not much remember the days of his life; because God answereth him in the joy of his heart.","words":[["H7235","For he shall not much",0,21],["H2142","remember",22,30],["H3117","the days",31,39],["H2416","of his life",40,51],["H0430","because God",53,64],["H6031","answereth",65,74],["H8057","him in the joy",75,89],["H3820","of his heart",90,102]]},"6:1":{"text":"There is an evil which I have seen under the sun, and it is common among men:","words":[["H3426","There is",0,8],["H7451","an evil",9,16],["H7200","which I have seen",17,34],["H8121","under the sun",35,48],["H7227","and it is common",50,66],["H0120","among men",67,76]]},"6:2":{"text":"A man to whom God hath given riches, wealth, and honour, so that he wanteth nothing for his soul of all that he desireth, yet God giveth him not power to eat thereof, but a stranger eateth it: this is vanity, and it is an evil disease.","words":[["H0376","A man",0,5],["H0430","to whom God",6,17],["H5414","hath given",18,28],["H6239","riches",29,35],["H5233","wealth",37,43],["H3519","and honour",45,55],["H2638","so that he wanteth",57,75],["H5315","nothing for his soul",76,96],["H0183","of all that he desireth",97,120],["H0430","yet God",122,129],["H7980","giveth him not power",130,150],["H0398","to eat",151,157],["H0376","thereof, but a stranger",158,181],["H5237","thereof, but a stranger",158,181],["H0398","eateth",182,188],["H1892","it: this is vanity",189,207],["H7451","and it is an evil",209,226],["H2483","disease",227,234]]},"6:3":{"text":"If a man beget an hundred children, and live many years, so that the days of his years be many, and his soul be not filled with good, and also that he have no burial; I say, that an untimely birth is better than he.","words":[["H0376","If a man",0,8],["H3205","beget",9,14],["H3967","an hundred",15,25],["H2421","children, and live",26,44],["H7227","many",45,49],["H8141","years",50,55],["H3117","so that the days",57,73],["H8141","of his years",74,86],["H7227","be many",87,94],["H5315","and his soul",96,108],["H7646","be not filled",109,122],["H2896","with good",123,132],["H6900","and also that he have no burial",134,165],["H0559","I say",167,172],["H5309","that an untimely birth",174,196],["H2896","is better",197,206]]},"6:4":{"text":"For he cometh in with vanity, and departeth in darkness, and his name shall be covered with darkness.","words":[["H0935","For he cometh",0,13],["H1892","in with vanity",14,28],["H3212","and departeth",30,43],["H2822","in darkness",44,55],["H8034","and his name",57,69],["H3680","shall be covered",70,86],["H2822","with darkness",87,100]]},"6:5":{"text":"Moreover he hath not seen the sun, nor known any thing: this hath more rest than the other.","words":[["H7200","Moreover he hath not seen",0,25],["H8121","the sun",26,33],["H3045","nor known",35,44],["H2088","any thing: this",45,60],["H5183","hath more rest",61,75],["H2088","than",76,80]]},"6:6":{"text":"Yea, though he live a thousand years twice told, yet hath he seen no good: do not all go to one place?","words":[["H0432","Yea, though",0,11],["H2421","he live",12,19],["H0505","a thousand",20,30],["H8141","years",31,36],["H6471","twice",37,42],["H7200","told, yet hath he seen",43,65],["H2896","no good",66,73],["H1980","do not all go",75,88],["H0259","to one",89,95],["H4725","place",96,101]]},"6:7":{"text":"All the labour of man is for his mouth, and yet the appetite is not filled.","words":[["H5999","All the labour",0,14],["H0120","of man",15,21],["H6310","is for his mouth",22,38],["H5315","and yet the appetite",40,60],["H4390","is not filled",61,74]]},"6:8":{"text":"For what hath the wise more than the fool? what hath the poor, that knoweth to walk before the living?","words":[["H2450","For what hath the wise",0,22],["H3148","more",23,27],["H3684","than the fool",28,41],["H6041","what hath the poor",43,61],["H3045","that knoweth",63,75],["H1980","to walk",76,83],["H2416","before the living",84,101]]},"6:9":{"text":"Better is the sight of the eyes than the wandering of the desire: this is also vanity and vexation of spirit.","words":[["H2896","Better",0,6],["H4758","is the sight",7,19],["H5869","of the eyes",20,31],["H1980","than the wandering",32,50],["H5315","of the desire",51,64],["H1892","this is also vanity",66,85],["H7469","and vexation",86,98],["H7307","of spirit",99,108]]},"6:10":{"text":"That which hath been is named already, and it is known that it is man: neither may he contend with him that is mightier than he.","words":[["H7121","That which hath been is named",0,29],["H8034","That which hath been is named",0,29],["H3528","already",30,37],["H3045","and it is known",39,54],["H0120","that it is man",55,69],["H3201","neither may",71,82],["H1777","he contend",83,93],["H8623","with him that is mightier",94,119]]},"6:11":{"text":"Seeing there be many things that increase vanity, what is man the better?","words":[["H3426","Seeing there be",0,15],["H7235","many",16,20],["H1697","things",21,27],["H7235","that increase",28,41],["H1892","vanity",42,48],["H0120","what is man",50,61],["H3148","the better",62,72]]},"6:12":{"text":"For who knoweth what is good for man in this life, all the days of his vain life which he spendeth as a shadow? for who can tell a man what shall be after him under the sun?","words":[["H3045","For who knoweth",0,15],["H2896","what is good",16,28],["H0120","for man",29,36],["H2416","in this life",37,49],["H4557","all",51,54],["H3117","the days",55,63],["H1892","of his vain",64,75],["H2416","life",76,80],["H6213","which he spendeth",81,98],["H6738","as a shadow",99,110],["H5046","for who can tell",112,128],["H0120","a man",129,134],["H0310","what shall be after",135,154],["H8121","him under the sun",155,172]]},"7:1":{"text":"A good name is better than precious ointment; and the day of death than the day of one's birth.","words":[["H8034","A good name",0,11],["H2896","is better",12,21],["H2896","than precious",22,35],["H8081","ointment",36,44],["H3117","and the day",46,57],["H4194","of death",58,66],["H3117","than the day",67,79],["H3205","of one's birth",80,94]]},"7:2":{"text":"It is better to go to the house of mourning, than to go to the house of feasting: for that is the end of all men; and the living will lay it to his heart.","words":[["H2896","It is better",0,12],["H3212","to go",13,18],["H1004","to the house",19,31],["H0060","of mourning",32,43],["H3212","than to go",45,55],["H1004","to the house",56,68],["H4960","of feasting",69,80],["H0834","for",82,85],["H5490","that is the end",86,101],["H0120","of all men",102,112],["H2416","and the living",114,128],["H5414","will lay",129,137],["H3820","it to his heart",138,153]]},"7:3":{"text":"Sorrow is better than laughter: for by the sadness of the countenance the heart is made better.","words":[["H3708","Sorrow",0,6],["H2896","is better",7,16],["H7814","than laughter",17,30],["H7455","for by the sadness",32,50],["H6440","of the countenance",51,69],["H3820","the heart",70,79],["H3190","is made better",80,94]]},"7:4":{"text":"The heart of the wise is in the house of mourning; but the heart of fools is in the house of mirth.","words":[["H3820","The heart",0,9],["H2450","of the wise",10,21],["H1004","is in the house",22,37],["H0060","of mourning",38,49],["H3820","but the heart",51,64],["H3684","of fools",65,73],["H1004","is in the house",74,89],["H8057","of mirth",90,98]]},"7:5":{"text":"It is better to hear the rebuke of the wise, than for a man to hear the song of fools.","words":[["H2896","It is better",0,12],["H8085","to hear",13,20],["H1606","the rebuke",21,31],["H2450","of the wise",32,43],["H0376","than for a man",45,59],["H8085","to hear",60,67],["H7892","the song",68,76],["H3684","of fools",77,85]]},"7:6":{"text":"For as the crackling of thorns under a pot, so is the laughter of the fool: this also is vanity.","words":[["H6963","For as the crackling",0,20],["H5518","of thorns",21,30],["H5518","under a pot",31,42],["H7814","so is the laughter",44,62],["H3684","of the fool",63,74],["H1892","this also is vanity",76,95]]},"7:7":{"text":"Surely oppression maketh a wise man mad; and a gift destroyeth the heart.","words":[["H6233","Surely oppression",0,17],["H2450","maketh a wise man",18,35],["H1984","mad",36,39],["H4979","and a gift",41,51],["H0006","destroyeth",52,62],["H3820","the heart",63,72]]},"7:8":{"text":"Better is the end of a thing than the beginning thereof: and the patient in spirit is better than the proud in spirit.","words":[["H2896","Better",0,6],["H0319","is the end",7,17],["H1697","of a thing",18,28],["H7225","than the beginning",29,47],["H0750","thereof: and the patient",48,72],["H7307","in spirit",73,82],["H2896","is better",83,92],["H1362","than the proud",93,107],["H7307","in spirit",108,117]]},"7:9":{"text":"Be not hasty in thy spirit to be angry: for anger resteth in the bosom of fools.","words":[["H0926","Be not hasty",0,12],["H7307","in thy spirit",13,26],["H3707","to be angry",27,38],["H3708","for anger",40,49],["H5117","resteth",50,57],["H2436","in the bosom",58,70],["H3684","of fools",71,79]]},"7:10":{"text":"Say not thou, What is the cause that the former days were better than these? for thou dost not enquire wisely concerning this.","words":[["H0559","Say",0,3],["H7223","not thou, What is the cause that the former",4,47],["H3117","days",48,52],["H2896","were better",53,64],["H7592","than these? for thou dost not enquire",65,102],["H2451","wisely",103,109]]},"7:11":{"text":"Wisdom is good with an inheritance: and by it there is profit to them that see the sun.","words":[["H2451","Wisdom",0,6],["H2896","is good",7,14],["H5159","with an inheritance",15,34],["H3148","and by it there is profit",36,61],["H7200","to them that see",62,78],["H8121","the sun",79,86]]},"7:12":{"text":"For wisdom is a defence, and money is a defence: but the excellency of knowledge is, that wisdom giveth life to them that have it.","words":[["H2451","For wisdom",0,10],["H6738","is a defence",11,23],["H3701","and money",25,34],["H6738","is a defence",35,47],["H3504","but the excellency",49,67],["H1847","of knowledge",68,80],["H2451","is, that wisdom",81,96],["H2421","giveth life",97,108],["H1167","to them that have",109,126]]},"7:13":{"text":"Consider the work of God: for who can make that straight, which he hath made crooked?","words":[["H7200","Consider",0,8],["H4639","the work",9,17],["H0430","of God",18,24],["H3201","for who can",26,37],["H8626","make that straight",38,56],["H5791","which he hath made crooked",58,84]]},"7:14":{"text":"In the day of prosperity be joyful, but in the day of adversity consider: God also hath set the one over against the other, to the end that man should find nothing after him.","words":[["H3117","In the day",0,10],["H2896","of prosperity",11,24],["H2896","be joyful",25,34],["H3117","but in the day",36,50],["H7451","of adversity",51,63],["H7200","consider",64,72],["H0430","God",74,77],["H6213","also hath set",78,91],["H5980","the one over against",92,112],["H1700","the other, to the end",113,134],["H0120","that man",135,143],["H4672","should find",144,155],["H3972","nothing",156,163],["H0310","after",164,169]]},"7:15":{"text":"All things have I seen in the days of my vanity: there is a just man that perisheth in his righteousness, and there is a wicked man that prolongeth his life in his wickedness.","words":[["H7200","All things have I seen",0,22],["H3117","in the days",23,34],["H1892","of my vanity",35,47],["H3426","there is",49,57],["H6662","a just",58,64],["H0006","man that perisheth",65,83],["H6664","in his righteousness",84,104],["H7563","and there is a wicked",106,127],["H0748","man that prolongeth",128,147],["H7451","his life in his wickedness",148,174]]},"7:16":{"text":"Be not righteous over much; neither make thyself over wise: why shouldest thou destroy thyself?","words":[["H6662","Be not righteous",0,16],["H7235","over much",17,26],["H3148","neither make thyself over",28,53],["H2449","wise",54,58],["H8074","why shouldest thou destroy",60,86]]},"7:17":{"text":"Be not over much wicked, neither be thou foolish: why shouldest thou die before thy time?","words":[["H7235","Be not over much",0,16],["H7561","wicked",17,23],["H5530","neither be thou foolish",25,48],["H4191","why shouldest thou die",50,72],["H6256","before thy time",73,88]]},"7:18":{"text":"It is good that thou shouldest take hold of this; yea, also from this withdraw not thine hand: for he that feareth God shall come forth of them all.","words":[["H2896","It is good",0,10],["H0270","that thou shouldest take hold",11,40],["H2088","of this; yea, also from this",41,69],["H3240","withdraw",70,78],["H3027","not thine hand",79,93],["H3373","for he that feareth",95,114],["H0430","God",115,118],["H3318","shall come forth",119,135]]},"7:19":{"text":"Wisdom strengtheneth the wise more than ten mighty men which are in the city.","words":[["H2451","Wisdom",0,6],["H5810","strengtheneth",7,20],["H2450","the wise",21,29],["H6235","more than ten",30,43],["H7989","mighty",44,50],["H5892","men which are in the city",51,76]]},"7:20":{"text":"For there is not a just man upon earth, that doeth good, and sinneth not.","words":[["H6662","For there is not a just",0,23],["H0120","man",24,27],["H0776","upon earth",28,38],["H6213","that doeth",40,50],["H2896","good",51,55],["H2398","and sinneth",57,68]]},"7:21":{"text":"Also take no heed unto all words that are spoken; lest thou hear thy servant curse thee:","words":[["H5414","Also take",0,9],["H3820","no heed",10,17],["H1697","unto all words",18,32],["H1696","that are spoken",33,48],["H8085","lest thou hear",50,64],["H5650","thy servant",65,76],["H7043","curse",77,82]]},"7:22":{"text":"For oftentimes also thine own heart knoweth that thou thyself likewise hast cursed others.","words":[["H6471","For oftentimes",0,14],["H7227","For oftentimes",0,14],["H3820","also thine own heart",15,35],["H3045","knoweth",36,43],["H7043","that thou thyself likewise hast cursed",44,82],["H0312","others",83,89]]},"7:23":{"text":"All this have I proved by wisdom: I said, I will be wise; but it was far from me.","words":[["H2090","All this",0,8],["H5254","have I proved",9,22],["H2451","by wisdom",23,32],["H0559","I said",34,40],["H2449","I will be wise",42,56],["H7350","but it was far",58,72]]},"7:24":{"text":"That which is far off, and exceeding deep, who can find it out?","words":[["H7350","That which is far off",0,21],["H6013","and exceeding deep",23,41],["H4672","who can find it out",43,62]]},"7:25":{"text":"I applied mine heart to know, and to search, and to seek out wisdom, and the reason of things, and to know the wickedness of folly, even of foolishness and madness:","words":[["H5437","I applied",0,9],["H3820","mine heart",10,20],["H3045","to know",21,28],["H8446","and to search",30,43],["H1245","and to seek out",45,60],["H2451","wisdom",61,67],["H2808","and the reason",69,83],["H3045","of things, and to know",84,106],["H7562","the wickedness",107,121],["H3689","of folly",122,130],["H5531","even of foolishness",132,151],["H1947","and madness",152,163]]},"7:26":{"text":"And I find more bitter than death the woman, whose heart is snares and nets, and her hands as bands: whoso pleaseth God shall escape from her; but the sinner shall be taken by her.","words":[["H4672","And I find",0,10],["H4751","more bitter",11,22],["H4194","than death",23,33],["H0802","the woman",34,43],["H3820","whose heart",45,56],["H4685","is snares",57,66],["H2764","and nets",67,75],["H3027","and her hands",77,90],["H0612","as bands",91,99],["H2896","whoso pleaseth",101,115],["H6440","whoso pleaseth",101,115],["H0430","God",116,119],["H4422","shall escape",120,132],["H2398","from her; but the sinner",133,157],["H3920","shall be taken",158,172]]},"7:27":{"text":"Behold, this have I found, saith the preacher, counting one by one, to find out the account:","words":[["H7200","Behold",0,6],["H4672","this have I found",8,25],["H0559","saith",27,32],["H6953","the preacher",33,45],["H0259","counting one",47,59],["H0259","by one",60,66],["H4672","to find out",68,79],["H2808","the account",80,91]]},"7:28":{"text":"Which yet my soul seeketh, but I find not: one man among a thousand have I found; but a woman among all those have I not found.","words":[["H5315","Which yet my soul",0,17],["H1245","seeketh",18,25],["H4672","but I find",27,37],["H0259","not: one",38,46],["H0120","man",47,50],["H0505","among a thousand",51,67],["H4672","have I found",68,80],["H0802","but a woman",82,93],["H4672","among all those have I not found",94,126]]},"7:29":{"text":"Lo, this only have I found, that God hath made man upright; but they have sought out many inventions.","words":[["H7200","Lo",0,2],["H0905","this only",4,13],["H4672","have I found",14,26],["H0430","that God",28,36],["H6213","hath made",37,46],["H0120","man",47,50],["H3477","upright",51,58],["H1245","but they have sought out",60,84],["H7227","many",85,89],["H2810","inventions",90,100]]},"8:1":{"text":"Who is as the wise man? and who knoweth the interpretation of a thing? a man's wisdom maketh his face to shine, and the boldness of his face shall be changed.","words":[["H2450","Who is as the wise",0,18],["H3045","man? and who knoweth",19,39],["H6592","the interpretation",40,58],["H1697","of a thing",59,69],["H0120","a man's",71,78],["H2451","wisdom",79,85],["H6440","maketh his face",86,101],["H0215","to shine",102,110],["H5797","and the boldness",112,128],["H6440","of his face",129,140],["H8132","shall be changed",141,157]]},"8:2":{"text":"I counsel thee to keep the king's commandment, and that in regard of the oath of God.","words":[["H8104","I counsel thee to keep",0,22],["H4428","the king's",23,33],["H6310","commandment",34,45],["H1700","and that in regard",47,65],["H7621","of the oath",66,77],["H0430","of God",78,84]]},"8:3":{"text":"Be not hasty to go out of his sight: stand not in an evil thing; for he doeth whatsoever pleaseth him.","words":[["H0926","Be not hasty",0,12],["H3212","to go out",13,22],["H6440","of his sight",23,35],["H5975","stand",37,42],["H7451","not in an evil",43,57],["H1697","thing",58,63],["H6213","for he doeth",65,77],["H2654","whatsoever pleaseth",78,97]]},"8:4":{"text":"Where the word of a king is, there is power: and who may say unto him, What doest thou?","words":[["H1697","Where the word",0,14],["H4428","of a king",15,24],["H7983","is, there is power",25,43],["H0559","and who may say",45,60],["H6213","unto him, What doest",61,81]]},"8:5":{"text":"Whoso keepeth the commandment shall feel no evil thing: and a wise man's heart discerneth both time and judgment.","words":[["H8104","Whoso keepeth",0,13],["H4687","the commandment",14,29],["H3045","shall feel",30,40],["H7451","no evil",41,48],["H1697","thing",49,54],["H2450","and a wise man's",56,72],["H3820","heart",73,78],["H3045","discerneth",79,89],["H6256","both time",90,99],["H4941","and judgment",100,112]]},"8:6":{"text":"Because to every purpose there is time and judgment, therefore the misery of man is great upon him.","words":[["H2656","Because to every purpose",0,24],["H3426","there is",25,33],["H6256","time",34,38],["H4941","and judgment",39,51],["H7451","therefore the misery",53,73],["H0120","of man",74,80],["H7227","is great",81,89]]},"8:7":{"text":"For he knoweth not that which shall be: for who can tell him when it shall be?","words":[["H3045","For he knoweth",0,14],["H5046","not that which shall be: for who can tell",15,56]]},"8:8":{"text":"There is no man that hath power over the spirit to retain the spirit; neither hath he power in the day of death: and there is no discharge in that war; neither shall wickedness deliver those that are given to it.","words":[["H0120","There is no man",0,15],["H7989","that hath power",16,31],["H7307","over the spirit",32,47],["H3607","to retain",48,57],["H7307","the spirit",58,68],["H7983","neither hath he power",70,91],["H3117","in the day",92,102],["H4194","of death",103,111],["H4917","and there is no discharge",113,138],["H4421","in that war",139,150],["H7562","neither shall wickedness",152,176],["H4422","deliver",177,184],["H1167","those that are given",185,205]]},"8:9":{"text":"All this have I seen, and applied my heart unto every work that is done under the sun: there is a time wherein one man ruleth over another to his own hurt.","words":[["H7200","All this have I seen",0,20],["H5414","and applied",22,33],["H3820","my heart",34,42],["H4639","unto every work",43,58],["H6213","that is done",59,71],["H8121","under the sun",72,85],["H6256","there is a time",87,102],["H0120","wherein one man",103,118],["H7980","ruleth",119,125],["H7451","over another to his own hurt",126,154]]},"8:10":{"text":"And so I saw the wicked buried, who had come and gone from the place of the holy, and they were forgotten in the city where they had so done: this is also vanity.","words":[["H3651","And so",0,6],["H7200","I saw",7,12],["H7563","the wicked",13,23],["H6912","buried",24,30],["H0935","who had come",32,44],["H1980","and gone",45,53],["H4725","from the place",54,68],["H6918","of the holy",69,80],["H7911","and they were forgotten",82,105],["H5892","in the city",106,117],["H6213","where they had so done",118,140],["H1892","this is also vanity",142,161]]},"8:11":{"text":"Because sentence against an evil work is not executed speedily, therefore the heart of the sons of men is fully set in them to do evil.","words":[["H6599","Because sentence",0,16],["H7451","against an evil",17,32],["H4639","work",33,37],["H6213","is not executed",38,53],["H4120","speedily",54,62],["H3820","therefore the heart",64,83],["H1121","of the sons",84,95],["H0120","of men",96,102],["H4390","is fully set",103,115],["H6213","in them to do",116,129],["H7451","evil",130,134]]},"8:12":{"text":"Though a sinner do evil an hundred times, and his days be prolonged, yet surely I know that it shall be well with them that fear God, which fear before him:","words":[["H2398","Though a sinner",0,15],["H6213","do",16,18],["H7451","evil",19,23],["H3967","an hundred times",24,40],["H0748","and his days be prolonged",42,67],["H3045","yet surely I know",69,86],["H2896","that it shall be well",87,108],["H3373","with them that fear",109,128],["H0430","God",129,132],["H3372","which fear",134,144],["H6440","before",145,151]]},"8:13":{"text":"But it shall not be well with the wicked, neither shall he prolong his days, which are as a shadow; because he feareth not before God.","words":[["H2896","But it shall not be well",0,24],["H7563","with the wicked",25,40],["H0748","neither shall he prolong",42,66],["H3117","his days",67,75],["H6738","which are as a shadow",77,98],["H3373","because he feareth",100,118],["H6440","not before",119,129],["H0430","God",130,133]]},"8:14":{"text":"There is a vanity which is done upon the earth; that there be just men, unto whom it happeneth according to the work of the wicked; again, there be wicked men, to whom it happeneth according to the work of the righteous: I said that this also is vanity.","words":[["H3426","There is",0,8],["H1892","a vanity",9,17],["H6213","which is done",18,31],["H0776","upon the earth",32,46],["H6662","that there be just",48,66],["H5060","men, unto whom it happeneth",67,94],["H4639","according to the work",95,116],["H7563","of the wicked",117,130],["H3426","again, there be",132,147],["H7563","wicked",148,154],["H5060","men, to whom it happeneth",155,180],["H4639","according to the work",181,202],["H6662","of the righteous",203,219],["H0559","I said",221,227],["H1571","that this also",228,242],["H1892","is vanity",243,252]]},"8:15":{"text":"Then I commended mirth, because a man hath no better thing under the sun, than to eat, and to drink, and to be merry: for that shall abide with him of his labour the days of his life, which God giveth him under the sun.","words":[["H7623","Then I commended",0,16],["H8057","mirth",17,22],["H0120","because a man",24,37],["H2896","hath no better thing",38,58],["H8121","under the sun",59,72],["H0398","than to eat",74,85],["H8354","and to drink",87,99],["H8055","and to be merry",101,116],["H3867","for that shall abide",118,138],["H5999","with him of his labour",139,161],["H3117","the days",162,170],["H2416","of his life",171,182],["H0430","which God",184,193],["H5414","giveth",194,200],["H8121","him under the sun",201,218]]},"8:16":{"text":"When I applied mine heart to know wisdom, and to see the business that is done upon the earth: (for also there is that neither day nor night seeth sleep with his eyes:)","words":[["H5414","When I applied",0,14],["H3820","mine heart",15,25],["H3045","to know",26,33],["H2451","wisdom",34,40],["H7200","and to see",42,52],["H6045","the business",53,65],["H6213","that is done",66,78],["H0776","upon the earth",79,93],["H3117","(for also there is that neither day",95,130],["H3915","nor night",131,140],["H7200","seeth",141,146],["H8142","sleep",147,152],["H5869","with his eyes",153,166]]},"8:17":{"text":"Then I beheld all the work of God, that a man cannot find out the work that is done under the sun: because though a man labour to seek it out, yet he shall not find it; yea further; though a wise man think to know it, yet shall he not be able to find it.","words":[["H7200","Then I beheld",0,13],["H4639","all the work",14,26],["H0430","of God",27,33],["H0120","that a man",35,45],["H3201","cannot",46,52],["H4672","find out",53,61],["H4639","the work",62,70],["H6213","that is done",71,83],["H8121","under the sun",84,97],["H0834","because",99,106],["H7945","though",107,113],["H0120","a man",114,119],["H5998","labour",120,126],["H1245","to seek it out",127,141],["H4672","yet he shall not find",143,164],["H2450","it; yea further; though a wise",165,195],["H0559","man think",196,205],["H3045","to know",206,213],["H3201","it, yet shall he not be able",214,242],["H4672","to find",243,250]]},"9:1":{"text":"For all this I considered in my heart even to declare all this, that the righteous, and the wise, and their works, are in the hand of God: no man knoweth either love or hatred by all that is before them.","words":[["H5414","For all this I considered",0,25],["H3820","in my heart",26,37],["H0952","even to declare",38,53],["H6662","all this, that the righteous",54,82],["H2450","and the wise",84,96],["H5652","and their works",98,113],["H3027","are in the hand",115,130],["H0430","of God",131,137],["H0120","no man",139,145],["H3045","knoweth",146,153],["H1571","either",154,160],["H0160","love",161,165],["H8135","or hatred",166,175],["H6440","by all that is before",176,197]]},"9:2":{"text":"All things come alike to all: there is one event to the righteous, and to the wicked; to the good and to the clean, and to the unclean; to him that sacrificeth, and to him that sacrificeth not: as is the good, so is the sinner; and he that sweareth, as he that feareth an oath.","words":[["H0259","All things come alike to all: there is one",0,42],["H4745","event",43,48],["H6662","to the righteous",49,65],["H7563","and to the wicked",67,84],["H2896","to the good",86,97],["H2889","and to the clean",98,114],["H2931","and to the unclean",116,134],["H2076","to him that sacrificeth",136,159],["H0834","and to him that",161,176],["H2076","sacrificeth",177,188],["H2896","not: as is the good",189,208],["H2398","so is the sinner",210,226],["H7650","and he that sweareth",228,248],["H3373","as he that feareth",250,268],["H7621","an oath",269,276]]},"9:3":{"text":"This is an evil among all things that are done under the sun, that there is one event unto all: yea, also the heart of the sons of men is full of evil, and madness is in their heart while they live, and after that they go to the dead.","words":[["H7451","This is an evil",0,15],["H6213","among all things that are done",16,46],["H8121","under the sun",47,60],["H0259","that there is one",62,79],["H4745","event",80,85],["H3820","unto all: yea, also the heart",86,115],["H1121","of the sons",116,127],["H0120","of men",128,134],["H4390","is full",135,142],["H7451","of evil",143,150],["H1947","and madness",152,163],["H3824","is in their heart",164,181],["H2416","while they live",182,197],["H0310","and after",199,208],["H4191","that they go to the dead",209,233]]},"9:4":{"text":"For to him that is joined to all the living there is hope: for a living dog is better than a dead lion.","words":[["H4310","For",0,3],["H3426","to him that is",4,18],["H2266","joined",19,25],["H0977","joined",19,25],["H2416","to all the living",26,43],["H0986","there is hope",44,57],["H2416","for a living",59,71],["H3611","dog",72,75],["H2896","is better",76,85],["H4191","than a dead",86,97],["H0738","lion",98,102]]},"9:5":{"text":"For the living know that they shall die: but the dead know not any thing, neither have they any more a reward; for the memory of them is forgotten.","words":[["H2416","For the living",0,14],["H3045","know",15,19],["H4191","that they shall die",20,39],["H4191","but the dead",41,53],["H3045","know",54,58],["H3972","not any thing",59,72],["H7939","neither have they any more a reward",74,109],["H2143","for the memory",111,125],["H7911","of them is forgotten",126,146]]},"9:6":{"text":"Also their love, and their hatred, and their envy, is now perished; neither have they any more a portion for ever in any thing that is done under the sun.","words":[["H0160","Also their love",0,15],["H8135","and their hatred",17,33],["H7068","and their envy",35,49],["H3528","is now",51,57],["H0006","perished",58,66],["H2506","neither have they any more a portion",68,104],["H5769","for ever",105,113],["H6213","in any thing that is done",114,139],["H8121","under the sun",140,153]]},"9:7":{"text":"Go thy way, eat thy bread with joy, and drink thy wine with a merry heart; for God now accepteth thy works.","words":[["H3212","Go thy way",0,10],["H0398","eat",12,15],["H3899","thy bread",16,25],["H8057","with joy",26,34],["H8354","and drink",36,45],["H3196","thy wine",46,54],["H2896","with a merry",55,67],["H3820","heart",68,73],["H0430","for God",75,82],["H3528","now",83,86],["H7521","accepteth",87,96],["H4639","thy works",97,106]]},"9:8":{"text":"Let thy garments be always white; and let thy head lack no ointment.","words":[["H0899","Let thy garments",0,16],["H6256","be always",17,26],["H3836","white",27,32],["H7218","and let thy head",34,50],["H2637","lack",51,55],["H8081","no ointment",56,67]]},"9:9":{"text":"Live joyfully with the wife whom thou lovest all the days of the life of thy vanity, which he hath given thee under the sun, all the days of thy vanity: for that is thy portion in this life, and in thy labour which thou takest under the sun.","words":[["H2416","Live",0,4],["H7200","joyfully",5,13],["H0802","with the wife",14,27],["H0157","whom thou lovest",28,44],["H3117","all the days",45,57],["H2416","of the life",58,69],["H1892","of thy vanity",70,83],["H5414","which he hath given",85,104],["H8121","thee under the sun",105,123],["H3117","all the days",125,137],["H1892","of thy vanity",138,151],["H2506","for that is thy portion",153,176],["H2416","in this life",177,189],["H5999","and in thy labour",191,208],["H6001","which thou takest",209,226],["H8121","under the sun",227,240]]},"9:10":{"text":"Whatsoever thy hand findeth to do, do it with thy might; for there is no work, nor device, nor knowledge, nor wisdom, in the grave, whither thou goest.","words":[["H3027","Whatsoever thy hand",0,19],["H4672","findeth",20,27],["H6213","to do",28,33],["H6213","do",35,37],["H3581","it with thy might",38,55],["H4639","for there is no work",57,77],["H2808","nor device",79,89],["H1847","nor knowledge",91,104],["H2451","nor wisdom",106,116],["H7585","in the grave",118,130],["H1980","whither thou goest",132,150]]},"9:11":{"text":"I returned, and saw under the sun, that the race is not to the swift, nor the battle to the strong, neither yet bread to the wise, nor yet riches to men of understanding, nor yet favour to men of skill; but time and chance happeneth to them all.","words":[["H7725","I returned",0,10],["H7200","and saw",12,19],["H8121","under the sun",20,33],["H4793","that the race",35,48],["H7031","is not to the swift",49,68],["H4421","nor the battle",70,84],["H1368","to the strong",85,98],["H3899","neither yet bread",100,117],["H2450","to the wise",118,129],["H6239","nor yet riches",131,145],["H0995","to men of understanding",146,169],["H2580","nor yet favour",171,185],["H3045","to men of skill",186,201],["H6256","but time",203,211],["H6294","and chance",212,222],["H7136","happeneth",223,232]]},"9:12":{"text":"For man also knoweth not his time: as the fishes that are taken in an evil net, and as the birds that are caught in the snare; so are the sons of men snared in an evil time, when it falleth suddenly upon them.","words":[["H0120","For man",0,7],["H3045","also knoweth",8,20],["H6256","not his time",21,33],["H1709","as the fishes",35,48],["H0270","that are taken",49,63],["H7451","in an evil",64,74],["H4685","net",75,78],["H6833","and as the birds",80,96],["H0270","that are caught",97,112],["H6341","in the snare",113,125],["H1992","so",127,129],["H1121","are the sons",130,142],["H0120","of men",143,149],["H3369","snared",150,156],["H7451","in an evil",157,167],["H6256","time",168,172],["H5307","when it falleth",174,189],["H6597","suddenly",190,198]]},"9:13":{"text":"This wisdom have I seen also under the sun, and it seemed great unto me:","words":[["H2090","This",0,4],["H2451","wisdom",5,11],["H7200","have I seen",12,23],["H8121","also under the sun",24,42],["H1419","and it seemed great",44,63]]},"9:14":{"text":"There was a little city, and few men within it; and there came a great king against it, and besieged it, and built great bulwarks against it:","words":[["H6996","There was a little",0,18],["H5892","city",19,23],["H4592","and few",25,32],["H0582","men",33,36],["H0935","within it; and there came",37,62],["H1419","a great",63,70],["H4428","king",71,75],["H5437","against it, and besieged",76,100],["H1129","it, and built",101,114],["H1419","great",115,120],["H4685","bulwarks",121,129]]},"9:15":{"text":"Now there was found in it a poor wise man, and he by his wisdom delivered the city; yet no man remembered that same poor man.","words":[["H4672","Now there was found",0,19],["H4542","in it a poor",20,32],["H2450","wise",33,37],["H0376","man",38,41],["H2451","and he by his wisdom",43,63],["H4422","delivered",64,73],["H5892","the city",74,82],["H0120","yet no man",84,94],["H2142","remembered",95,105],["H4542","that same poor",106,120],["H0376","man",121,124]]},"9:16":{"text":"Then said I, Wisdom is better than strength: nevertheless the poor man's wisdom is despised, and his words are not heard.","words":[["H0559","Then said",0,9],["H2451","I, Wisdom",10,19],["H2896","is better",20,29],["H1369","than strength",30,43],["H4542","nevertheless the poor man's",45,72],["H2451","wisdom",73,79],["H0959","is despised",80,91],["H1697","and his words",93,106],["H8085","are not heard",107,120]]},"9:17":{"text":"The words of wise men are heard in quiet more than the cry of him that ruleth among fools.","words":[["H1697","The words",0,9],["H2450","of wise",10,17],["H8085","men are heard",18,31],["H5183","in quiet",32,40],["H2201","more than the cry",41,58],["H4910","of him that ruleth",59,77],["H3684","among fools",78,89]]},"9:18":{"text":"Wisdom is better than weapons of war: but one sinner destroyeth much good.","words":[["H2451","Wisdom",0,6],["H2896","is better",7,16],["H3627","than weapons",17,29],["H7128","of war",30,36],["H0259","but one",38,45],["H2398","sinner",46,52],["H0006","destroyeth",53,63],["H7235","much",64,68],["H2896","good",69,73]]},"10:1":{"text":"Dead flies cause the ointment of the apothecary to send forth a stinking savour: so doth a little folly him that is in reputation for wisdom and honour.","words":[["H4194","Dead",0,4],["H2070","flies",5,10],["H8081","cause the ointment",11,29],["H7543","of the apothecary",30,47],["H5042","to send forth",48,61],["H0887","a stinking savour",62,79],["H4592","so doth a little",81,97],["H5531","folly",98,103],["H3368","him that is in reputation",104,129],["H2451","for wisdom",130,140],["H3519","and honour",141,151]]},"10:2":{"text":"A wise man's heart is at his right hand; but a fool's heart at his left.","words":[["H2450","A wise man's",0,12],["H3820","heart",13,18],["H3225","is at his right hand",19,39],["H3684","but a fool's",41,53],["H3820","heart",54,59],["H8040","at his left",60,71]]},"10:3":{"text":"Yea also, when he that is a fool walketh by the way, his wisdom faileth him, and he saith to every one that he is a fool.","words":[["H5530","Yea also, when he that is a fool",0,32],["H1980","walketh",33,40],["H1870","by the way",41,51],["H3820","his wisdom",53,63],["H2638","faileth",64,71],["H0559","him, and he saith",72,89],["H5530","to every one that he is a fool",90,120]]},"10:4":{"text":"If the spirit of the ruler rise up against thee, leave not thy place; for yielding pacifieth great offences.","words":[["H7307","If the spirit",0,13],["H4910","of the ruler",14,26],["H5927","rise up",27,34],["H3240","against thee, leave",35,54],["H4725","not thy place",55,68],["H4832","for yielding",70,82],["H3240","pacifieth",83,92],["H1419","great",93,98],["H2399","offences",99,107]]},"10:5":{"text":"There is an evil which I have seen under the sun, as an error which proceedeth from the ruler:","words":[["H3426","There is",0,8],["H7451","an evil",9,16],["H7200","which I have seen",17,34],["H8121","under the sun",35,48],["H7684","as an error",50,61],["H3318","which proceedeth",62,78],["H6440","from",79,83],["H7989","the ruler",84,93]]},"10:6":{"text":"Folly is set in great dignity, and the rich sit in low place.","words":[["H5529","Folly",0,5],["H5414","is set",6,12],["H7227","in great",13,21],["H4791","dignity",22,29],["H6223","and the rich",31,43],["H3427","sit",44,47],["H8216","in low place",48,60]]},"10:7":{"text":"I have seen servants upon horses, and princes walking as servants upon the earth.","words":[["H7200","I have seen",0,11],["H5650","servants",12,20],["H5483","upon horses",21,32],["H8269","and princes",34,45],["H1980","walking",46,53],["H5650","as servants",54,65],["H0776","upon the earth",66,80]]},"10:8":{"text":"He that diggeth a pit shall fall into it; and whoso breaketh an hedge, a serpent shall bite him.","words":[["H2658","He that diggeth",0,15],["H1475","a pit",16,21],["H5307","shall fall",22,32],["H6555","into it; and whoso breaketh",33,60],["H1447","an hedge",61,69],["H5175","a serpent",71,80],["H5391","shall bite",81,91]]},"10:9":{"text":"Whoso removeth stones shall be hurt therewith; and he that cleaveth wood shall be endangered thereby.","words":[["H5265","Whoso removeth",0,14],["H0068","stones",15,21],["H6087","shall be hurt",22,35],["H1234","therewith; and he that cleaveth",36,67],["H6086","wood",68,72],["H5533","shall be endangered",73,92]]},"10:10":{"text":"If the iron be blunt, and he do not whet the edge, then must he put to more strength: but wisdom is profitable to direct.","words":[["H1270","If the iron",0,11],["H6949","be blunt",12,20],["H7043","and he do not whet",22,40],["H6440","the edge",41,49],["H1396","then must he put",51,67],["H2428","to more strength",68,84],["H2451","but wisdom",86,96],["H3504","is profitable",97,110],["H3787","to direct",111,120]]},"10:11":{"text":"Surely the serpent will bite without enchantment; and a babbler is no better.","words":[["H5175","Surely the serpent",0,18],["H5391","will bite",19,28],["H3908","without enchantment",29,48],["H3956","and a babbler",50,63],["H1167","and a babbler",50,63],["H3504","is no better",64,76]]},"10:12":{"text":"The words of a wise man's mouth are gracious; but the lips of a fool will swallow up himself.","words":[["H1697","The words",0,9],["H2450","of a wise man's",10,25],["H6310","mouth",26,31],["H2580","are gracious",32,44],["H8193","but the lips",46,58],["H3684","of a fool",59,68],["H1104","will swallow up",69,84]]},"10:13":{"text":"The beginning of the words of his mouth is foolishness: and the end of his talk is mischievous madness.","words":[["H8462","The beginning",0,13],["H1697","of the words",14,26],["H6310","of his mouth",27,39],["H5531","is foolishness",40,54],["H0319","and the end",56,67],["H6310","of his talk",68,79],["H7451","is mischievous",80,94],["H1948","madness",95,102]]},"10:14":{"text":"A fool also is full of words: a man cannot tell what shall be; and what shall be after him, who can tell him?","words":[["H5530","A fool",0,6],["H7235","also is full",7,19],["H1697","of words",20,28],["H0120","a man",30,35],["H3045","cannot tell",36,47],["H0310","what shall be; and what shall be after",48,86],["H5046","him, who can tell",87,104]]},"10:15":{"text":"The labour of the foolish wearieth every one of them, because he knoweth not how to go to the city.","words":[["H5999","The labour",0,10],["H3684","of the foolish",11,25],["H3021","wearieth",26,34],["H3045","every one of them, because he knoweth",35,72],["H3212","not how to go",73,86],["H5892","to the city",87,98]]},"10:16":{"text":"Woe to thee, O land, when thy king is a child, and thy princes eat in the morning!","words":[["H0337","Woe",0,3],["H0776","to thee, O land",4,19],["H4428","when thy king",21,34],["H5288","is a child",35,45],["H8269","and thy princes",47,62],["H0398","eat",63,66],["H1242","in the morning",67,81]]},"10:17":{"text":"Blessed art thou, O land, when thy king is the son of nobles, and thy princes eat in due season, for strength, and not for drunkenness!","words":[["H0835","Blessed",0,7],["H0776","art thou, O land",8,24],["H4428","when thy king",26,39],["H1121","is the son",40,50],["H2715","of nobles",51,60],["H8269","and thy princes",62,77],["H0398","eat",78,81],["H6256","in due season",82,95],["H1369","for strength",97,109],["H8358","and not for drunkenness",111,134]]},"10:18":{"text":"By much slothfulness the building decayeth; and through idleness of the hands the house droppeth through.","words":[["H6103","By much slothfulness",0,20],["H4746","the building",21,33],["H4355","decayeth",34,42],["H8220","and through idleness",44,64],["H3027","of the hands",65,77],["H1004","the house",78,87],["H1811","droppeth through",88,104]]},"10:19":{"text":"A feast is made for laughter, and wine maketh merry: but money answereth all things.","words":[["H3899","A feast",0,7],["H6213","is made",8,15],["H7814","for laughter",16,28],["H3196","and wine",30,38],["H8055","maketh merry",39,51],["H2416","maketh merry",39,51],["H3701","but money",53,62],["H6030","answereth",63,72]]},"10:20":{"text":"Curse not the king, no not in thy thought; and curse not the rich in thy bedchamber: for a bird of the air shall carry the voice, and that which hath wings shall tell the matter.","words":[["H7043","Curse",0,5],["H4428","not the king",6,18],["H4093","no not in thy thought",20,41],["H7043","and curse",43,52],["H6223","not the rich",53,65],["H2315","in thy bedchamber",66,83],["H4904","in thy bedchamber",66,83],["H5775","for a bird",85,95],["H8064","of the air",96,106],["H3212","shall carry",107,118],["H6963","the voice",119,128],["H1167","and that which hath",130,149],["H3671","wings",150,155],["H5046","shall tell",156,166],["H1697","the matter",167,177]]},"11:1":{"text":"Cast thy bread upon the waters: for thou shalt find it after many days.","words":[["H7971","Cast",0,4],["H3899","thy bread",5,14],["H6440","upon",15,19],["H4325","the waters",20,30],["H4672","for thou shalt find",32,51],["H7230","it after many",52,65],["H3117","days",66,70]]},"11:2":{"text":"Give a portion to seven, and also to eight; for thou knowest not what evil shall be upon the earth.","words":[["H5414","Give",0,4],["H2506","a portion",5,14],["H7651","to seven",15,23],["H8083","and also to eight",25,42],["H3045","for thou knowest",44,60],["H7451","not what evil",61,74],["H0776","shall be upon the earth",75,98]]},"11:3":{"text":"If the clouds be full of rain, they empty themselves upon the earth: and if the tree fall toward the south, or toward the north, in the place where the tree falleth, there it shall be.","words":[["H5645","If the clouds",0,13],["H4390","be full",14,21],["H1653","of rain",22,29],["H7324","they empty",31,41],["H0776","themselves upon the earth",42,67],["H6086","and if the tree",69,84],["H5307","fall",85,89],["H1864","toward the south",90,106],["H6828","or toward the north",108,127],["H4725","in the place",129,141],["H6086","where the tree",142,156],["H5307","falleth",157,164],["H1933","there it shall be",166,183]]},"11:4":{"text":"He that observeth the wind shall not sow; and he that regardeth the clouds shall not reap.","words":[["H8104","He that observeth",0,17],["H7307","the wind",18,26],["H2232","shall not sow",27,40],["H7200","and he that regardeth",42,63],["H5645","the clouds",64,74],["H7114","shall not reap",75,89]]},"11:5":{"text":"As thou knowest not what is the way of the spirit, nor how the bones do grow in the womb of her that is with child: even so thou knowest not the works of God who maketh all.","words":[["H3045","As thou knowest",0,15],["H1870","not what is the way",16,35],["H7307","of the spirit",36,49],["H6106","nor how the bones",51,68],["H0990","do grow in the womb",69,88],["H4392","of her that is with child",89,114],["H3045","even so thou knowest",116,136],["H4639","not the works",137,150],["H0430","of God",151,157],["H6213","who maketh",158,168]]},"11:6":{"text":"In the morning sow thy seed, and in the evening withhold not thine hand: for thou knowest not whether shall prosper, either this or that, or whether they both shall be alike good.","words":[["H1242","In the morning",0,14],["H2232","sow",15,18],["H2233","thy seed",19,27],["H6153","and in the evening",29,47],["H3240","withhold",48,56],["H3027","not thine hand",57,71],["H3045","for thou knowest",73,89],["H0335","not whether",90,101],["H3787","shall prosper",102,115],["H8147","either this or that, or whether they both",117,158],["H0259","shall be alike",159,173],["H2896","good",174,178]]},"11:7":{"text":"Truly the light is sweet, and a pleasant thing it is for the eyes to behold the sun:","words":[["H0216","Truly the light",0,15],["H4966","is sweet",16,24],["H2896","and a pleasant",26,40],["H5869","thing it is for the eyes",41,65],["H7200","to behold",66,75],["H8121","the sun",76,83]]},"11:8":{"text":"But if a man live many years, and rejoice in them all; yet let him remember the days of darkness; for they shall be many. All that cometh is vanity.","words":[["H0120","But if a man",0,12],["H2421","live",13,17],["H7235","many",18,22],["H8141","years",23,28],["H8055","and rejoice",30,41],["H2142","in them all; yet let him remember",42,75],["H3117","the days",76,84],["H2822","of darkness",85,96],["H7235","for they shall be many",98,120],["H0935","All that cometh",122,137],["H1892","is vanity",138,147]]},"11:9":{"text":"Rejoice, O young man, in thy youth; and let thy heart cheer thee in the days of thy youth, and walk in the ways of thine heart, and in the sight of thine eyes: but know thou, that for all these things God will bring thee into judgment.","words":[["H8055","Rejoice",0,7],["H0970","O young man",9,20],["H3208","in thy youth",22,34],["H3820","and let thy heart",36,53],["H2895","cheer",54,59],["H3117","thee in the days",60,76],["H0979","of thy youth",77,89],["H1980","and walk",91,99],["H1870","in the ways",100,111],["H3820","of thine heart",112,126],["H4758","and in the sight",128,144],["H5869","of thine eyes",145,158],["H3045","but know",160,168],["H0430","thou, that for all these things God",169,204],["H0935","will bring",205,215],["H4941","thee into judgment",216,234]]},"11:10":{"text":"Therefore remove sorrow from thy heart, and put away evil from thy flesh: for childhood and youth are vanity.","words":[["H5493","Therefore remove",0,16],["H3708","sorrow",17,23],["H3820","from thy heart",24,38],["H5674","and put away",40,52],["H7451","evil",53,57],["H1320","from thy flesh",58,72],["H3208","for childhood",74,87],["H7839","and youth",88,97],["H1892","are vanity",98,108]]},"12:1":{"text":"Remember now thy Creator in the days of thy youth, while the evil days come not, nor the years draw nigh, when thou shalt say, I have no pleasure in them;","words":[["H2142","Remember",0,8],["H1254","now thy Creator",9,24],["H3117","in the days",25,36],["H0979","of thy youth",37,49],["H7451","while the evil",51,65],["H3117","days",66,70],["H0935","come",71,75],["H8141","not, nor the years",76,94],["H5060","draw nigh",95,104],["H0559","when thou shalt say",106,125],["H2656","I have no pleasure",127,145]]},"12:2":{"text":"While the sun, or the light, or the moon, or the stars, be not darkened, nor the clouds return after the rain:","words":[["H8121","While the sun",0,13],["H0216","or the light",15,27],["H3394","or the moon",29,40],["H3556","or the stars",42,54],["H2821","be not darkened",56,71],["H5645","nor the clouds",73,87],["H7725","return",88,94],["H0310","after",95,100],["H1653","the rain",101,109]]},"12:3":{"text":"In the day when the keepers of the house shall tremble, and the strong men shall bow themselves, and the grinders cease because they are few, and those that look out of the windows be darkened,","words":[["H3117","In the day",0,10],["H8104","when the keepers",11,27],["H1004","of the house",28,40],["H2111","shall tremble",41,54],["H2428","and the strong",56,70],["H0582","men",71,74],["H5791","shall bow",75,84],["H2912","themselves, and the grinders",85,113],["H0988","cease",114,119],["H4591","because they are few",120,140],["H7200","and those that look out",142,165],["H0699","of the windows",166,180],["H2821","be darkened",181,192]]},"12:4":{"text":"And the doors shall be shut in the streets, when the sound of the grinding is low, and he shall rise up at the voice of the bird, and all the daughters of musick shall be brought low;","words":[["H1817","And the doors",0,13],["H5462","shall be shut",14,27],["H7784","in the streets",28,42],["H6963","when the sound",44,58],["H2913","of the grinding",59,74],["H8217","is low",75,81],["H6965","and he shall rise up",83,103],["H6963","at the voice",104,116],["H6833","of the bird",117,128],["H1323","and all the daughters",130,151],["H7892","of musick",152,161],["H7817","shall be brought low",162,182]]},"12:5":{"text":"Also when they shall be afraid of that which is high, and fears shall be in the way, and the almond tree shall flourish, and the grasshopper shall be a burden, and desire shall fail: because man goeth to his long home, and the mourners go about the streets:","words":[["H3372","Also when they shall be afraid",0,30],["H1364","of that which is high",31,52],["H2849","and fears",54,63],["H1870","shall be in the way",64,83],["H8247","and the almond tree",85,104],["H5006","shall flourish",105,119],["H2284","and the grasshopper",121,140],["H5445","shall be a burden",141,158],["H0035","and desire",160,170],["H6565","shall fail",171,181],["H0120","because man",183,194],["H1980","goeth",195,200],["H5769","to his long",201,212],["H1004","home",213,217],["H5594","and the mourners",219,235],["H5437","go about",236,244],["H7784","the streets",245,256]]},"12:6":{"text":"Or ever the silver cord be loosed, or the golden bowl be broken, or the pitcher be broken at the fountain, or the wheel broken at the cistern.","words":[["H3808","Or ever",0,7],["H3701","the silver",8,18],["H2256","cord",19,23],["H7576","be loosed",24,33],["H7368","be loosed",24,33],["H2091","or the golden",35,48],["H1543","bowl",49,53],["H7533","be broken",54,63],["H3537","or the pitcher",65,79],["H7665","be broken",80,89],["H4002","at the fountain",90,105],["H1534","or the wheel",107,119],["H7533","broken",120,126],["H0953","at the cistern",127,141]]},"12:7":{"text":"Then shall the dust return to the earth as it was: and the spirit shall return unto God who gave it.","words":[["H6083","Then shall the dust",0,19],["H7725","return",20,26],["H0776","to the earth",27,39],["H7307","as it was: and the spirit",40,65],["H7725","shall return",66,78],["H0430","unto God",79,87],["H5414","who gave",88,96]]},"12:8":{"text":"Vanity of vanities, saith the preacher; all is vanity.","words":[["H1892","Vanity",0,6],["H1892","of vanities",7,18],["H0559","saith",20,25],["H6953","the preacher",26,38],["H1892","all is vanity",40,53]]},"12:9":{"text":"And moreover, because the preacher was wise, he still taught the people knowledge; yea, he gave good heed, and sought out, and set in order many proverbs.","words":[["H3148","And moreover",0,12],["H6953","because the preacher",14,34],["H2450","was wise",35,43],["H3925","he still taught",45,60],["H5971","the people",61,71],["H1847","knowledge",72,81],["H0239","yea, he gave good heed",83,105],["H2713","and sought out",107,121],["H8626","and set in order",123,139],["H7235","many",140,144],["H4912","proverbs",145,153]]},"12:10":{"text":"The preacher sought to find out acceptable words: and that which was written was upright, even words of truth.","words":[["H6953","The preacher",0,12],["H1245","sought",13,19],["H4672","to find out",20,31],["H2656","acceptable",32,42],["H1697","words",43,48],["H3789","and that which was written",50,76],["H3476","was upright",77,88],["H1697","even words",90,100],["H0571","of truth",101,109]]},"12:11":{"text":"The words of the wise are as goads, and as nails fastened by the masters of assemblies, which are given from one shepherd.","words":[["H1697","The words",0,9],["H2450","of the wise",10,21],["H1861","are as goads",22,34],["H4930","and as nails",36,48],["H5193","fastened",49,57],["H1167","by the masters",58,72],["H0627","of assemblies",73,86],["H5414","which are given",88,103],["H0259","from one",104,112],["H7462","shepherd",113,121]]},"12:12":{"text":"And further, by these, my son, be admonished: of making many books there is no end; and much study is a weariness of the flesh.","words":[["H3148","And further",0,11],["H1992","by these",13,21],["H1121","my son",23,29],["H2094","be admonished",31,44],["H6213","of making",46,55],["H7235","many",56,60],["H5612","books",61,66],["H7093","there is no end",67,82],["H7235","and much",84,92],["H3854","study",93,98],["H3024","is a weariness",99,113],["H1320","of the flesh",114,126]]},"12:13":{"text":"Let us hear the conclusion of the whole matter: Fear God, and keep his commandments: for this is the whole duty of man.","words":[["H8085","Let us hear",0,11],["H5490","the conclusion",12,26],["H1697","of the whole matter",27,46],["H3372","Fear",48,52],["H0430","God",53,56],["H8104","and keep",58,66],["H4687","his commandments",67,83],["H0120","for this is the whole duty of man",85,118]]},"12:14":{"text":"For God shall bring every work into judgment, with every secret thing, whether it be good, or whether it be evil.","words":[["H0430","For God",0,7],["H0935","shall bring",8,19],["H4639","every work",20,30],["H4941","into judgment",31,44],["H5956","with every secret thing",46,69],["H2896","whether it be good",71,89],["H7451","or whether it be evil",91,112]]}}};
